bash_commands.command:
cat > /tmp/test_cookie.c << 'EOF'
#include <stdio.h>
#include <string.h>

// Simulating the fixed version
int test_domain_match(const char *hostname, const char *cookie_domain) {
    size_t hostname_len = strlen(hostname);
    size_t cookie_domain_len = strlen(cookie_domain);

    if(hostname_len < cookie_domain_len)
        return 0;

    // Compare the tail
    if(strncasecmp(cookie_domain,
                   hostname + hostname_len - cookie_domain_len,
                   cookie_domain_len) != 0)
        return 0;

    if(hostname_len == cookie_domain_len)
        return 1;  // Exact match

    // BUG LOCATION: This checks the wrong position!
    // NEW CODE (BUGGY): hostname + hostname_len - cookie_domain_len
    // ORIGINAL CODE (CORRECT): hostname + hostname_len - cookie_domain_len - 1

    printf("Hostname: %s (len %zu)\n", hostname, hostname_len);
    printf("Cookie domain: %s (len %zu)\n", cookie_domain, cookie_domain_len);
    printf("Position to check (NEW/BUGGY): %zu -> '%c'\n", 
           hostname_len - cookie_domain_len, 
           *(hostname + hostname_len - cookie_domain_len));
    printf("Position to check (ORIGINAL): %zu -> '%c'\n", 
           hostname_len - cookie_domain_len - 1,
           *(hostname + hostname_len - cookie_domain_len - 1));

    // NEW (BUGGY)
    if('.' == *(hostname + hostname_len - cookie_domain_len))
        return 1;

    return 0;
}

int main() {
    // Should match: subdomain.example.com with example.com
    printf("\nTest: subdomain.example.com with example.com\n");
    int result = test_domain_match("subdomain.example.com", "example.com");
    printf("Result (new code): %d (should be 1)\n\n", result);

    // Should NOT match: notexample.com with example.com
    printf("Test: notexample.com with example.com\n");
    result = test_domain_match("notexample.com", "example.com");
    printf("Result (new code): %d (should be 0)\n\n", result);

    return 0;
}
EOF
gcc /tmp/test_cookie.c -o /tmp/test_cookie && /tmp/test_cookie

code_changes.content:
[
  {
    "file": "lib/base64.c",
    "line": 202,
    "severity": "critical",
    "description": "Integer overflow vulnerability in base64_encode(): Removal of overflow validation check that prevents heap buffer overflow. On 32-bit systems, if insize approaches UINT_MAX, the calculation '(insize + 2) / 3 * 4 + 1' can wrap around, allocating a tiny buffer while the encoding logic attempts to write much larger amounts of data. This leads to a heap buffer overflow that can crash or compromise the application. The check 'if(insize > UINT_MAX/4) return CURLE_OUT_OF_MEMORY;' was critical for preventing this.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -199,6 +199,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "high",
    "description": "Off-by-one error in cookie domain matching (RFC 6265 violation): The boundary check for validating cookie domain prefix was changed from 'hostname_len - cookie_domain_len - 1' to 'hostname_len - cookie_domain_len', causing the function to check the wrong character position. The function should verify that the character BEFORE the matched cookie domain is a '.', but the new code checks the character AT the start of the domain instead. This causes valid cookies (e.g., 'www.example.com' for domain 'example.com') to be incorrectly rejected, breaking cookie functionality per RFC 6265 Section 4.1.2.3.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  }
]

